const items = $input.all();
const newItems = [];

// --- 配置 Cookie 文件路径 ---
// 将这些路径修改为你实际存放 Cookie 文件的路径
const douyinCookiePath = "/home/node/cookies/douyin_cookies.txt";
const youtubeCookiePath = "/home/node/cookies/youtube_cookies.txt"; 
// 为其他平台添加更多 Cookie 路径（如果需要）
// const tiktokCookiePath = "/home/node/cookies/tiktok_cookies.txt";

console.log("youtubeCookiePath is: [" + youtubeCookiePath + "]"); // 调试

for (let item of items) {
  const videoLink = item.json.video_link; 
  let platform = "unknown";
  let audioFilePath = "";
  let videoId = ""; 
  let ytdlpCommand = "";
  let cookiesArgument = ""; // 用于存放 cookie 参数

  if (!videoLink) {
	item.json.error = "Video link is missing.";
	newItems.push(item);
	continue;
  }

  videoId = new Date().getTime().toString() + Math.random().toString(36).substring(2, 15);
  const baseAudioFilename = `audio_${videoId}`;
  const audioOutputTemplate = `/home/node/files/${baseAudioFilename}.%(ext)s`;
  const expectedAudioFormat = "m4a"; // 确保这与你的子流程期望一致
  const finalAudioPath = `/home/node/files/${baseAudioFilename}.mp3`;

  if (videoLink.includes("youtube.com") || videoLink.includes("youtu.be")) {
	platform = "youtube";
	console.log("Platform detected: youtube"); // 调试
	if (youtubeCookiePath && youtubeCookiePath.trim() !== "") { // 更严格的检查
	  cookiesArgument = ` --cookies "${youtubeCookiePath}" `;
	  console.log("Cookies argument set for YouTube: [" + cookiesArgument + "]"); // 调试
	} else {
	  console.log("youtubeCookiePath is not set or empty, no cookies for YouTube."); // 调试
	}
  } else if (videoLink.includes("bilibili.com")) {
	platform = "bilibili";
	// Bilibili 通常不需要 cookie，除非是会员视频等特殊情况
  } else if (videoLink.includes("tiktok.com")) {
	platform = "tiktok";
	// if (tiktokCookiePath) {
	//   cookiesArgument = ` --cookies "${tiktokCookiePath}" `;
	// }
  } else if (videoLink.includes("douyin.com")) {
	platform = "douyin";
	if (douyinCookiePath) {
	  cookiesArgument = ` --cookies "${douyinCookiePath}" `;
	} else {
	  // 如果没有为抖音配置cookie路径，可以记录一个警告或错误
	  console.warn("Douyin link detected, but no douyinCookiePath configured.");
	  item.json.warning = "Douyin link detected, but no cookie path configured for download.";
	}
  }
  // TODO: Add detection for other platforms

if (platform !== "unknown") {
  // 强制使用 mp3 和 64k 比特率，确保 25MB 限制内能塞下更长的视频（约50分钟）
  ytdlpCommand = `yt-dlp \
  --no-check-certificate \
  ${cookiesArgument} \
  -x --audio-format "mp3" --audio-quality 64K \
  --force-overwrites --no-playlist \
  --output "${audioOutputTemplate}" \
  "${videoLink}"`;

	console.log("Constructed ytdlpCommand: [" + ytdlpCommand + "]"); // 调试
	audioFilePath = finalAudioPath;
  } else {
	item.json.error = `Unsupported video platform for link: ${videoLink}`;
  }

  item.json.platform = platform;
  item.json.ytdlp_command = ytdlpCommand.trim(); // trim() 移除可能的多余空格
  item.json.expected_audio_file_path = audioFilePath;
  item.json.video_id_for_filename = videoId;

  newItems.push(item);
}
return newItems;

const items = $input.all();
const MAX_AI_RETRIES = 3;

for (let item of items) {
  // 保存原始 transcript 以备重试使用（如果当前item里没有，尝试从上游找回）
  let original_video_transcript = item.json.video_transcript;
  if (!original_video_transcript) {
      try {
          original_video_transcript = $("Switch: AI Parse Retry?").item.json.video_transcript;
      } catch(e) {}
  }

  // --- [修复核心]：找回被 AI Agent 吞掉的 ai_retry_count ---
  let currentRetryCount = 0;

  if (item.json.ai_retry_count !== undefined) {
      // 如果当前 JSON 里有（第一次运行通常有），直接用
      currentRetryCount = item.json.ai_retry_count;
  } else {
      // 如果当前 JSON 里没有（说明刚经过 AI Agent，数据被清洗了）
      // 我们通过 n8n 的上下文引用，去上一个 Switch 节点里找回计数
      try {
          const previousContext = $("Switch: AI Parse Retry?").item;
          if (previousContext && previousContext.json.ai_retry_count !== undefined) {
              currentRetryCount = previousContext.json.ai_retry_count;
          }
      } catch (e) {
          console.log("无法恢复 ai_retry_count，将重置为 0");
      }
  }

  item.json.ai_retry_count = currentRetryCount;
  // -------------------------------------------------------

  item.json.trigger_ai_retry = false;
  item.json.max_ai_retries_for_prompt = MAX_AI_RETRIES;

  let parsedDataForNextNode = {
    summary: "Error: AI output processing did not complete as expected.",
    note: "Error: AI output processing did not complete as expected."
  };

  item.json.parsing_error_details = null;

  // 检查是否有错误字段（来自上游节点）
  if (item.json.error) {
    // 有错误时，如果还没达到最大重试次数，则重试
    if (item.json.ai_retry_count < MAX_AI_RETRIES) {
      item.json.ai_retry_count = item.json.ai_retry_count + 1;
      item.json.trigger_ai_retry = true;
      item.json.parsing_error_details = `上游错误，第${item.json.ai_retry_count}次重试: ${item.json.error}`;
      // 清除错误字段，准备重试
      delete item.json.error;
    } else {
      item.json.trigger_ai_retry = false;
      item.json.parsing_error_details = `上游错误，已达最大重试次数: ${item.json.error}`;
    }
    item.json.output = parsedDataForNextNode;

    // 确保 transcript 存在以便 AI 再次读取
    item.json.video_transcript = original_video_transcript;
    continue;
  }

  // 正常的AI输出处理逻辑
  let rawAiStringFromAgent;
  // 这里的 item.json.output 来自 AI Agent
  if (item.json && item.json.hasOwnProperty('output') && typeof item.json.output === 'string') {
    rawAiStringFromAgent = item.json.output;
  } else {
    item.json.parsing_error_details = "AI输出不是字符串或缺失";
    item.json.output = parsedDataForNextNode;
    // 错误处理逻辑也需要防止死循环
     if (item.json.ai_retry_count < MAX_AI_RETRIES) {
         item.json.ai_retry_count += 1;
         item.json.trigger_ai_retry = true;
     }
    item.json.video_transcript = original_video_transcript;
    continue;
  }

  // 清理AI输出
  let textToParse = rawAiStringFromAgent;
  // 移除 <think> 标签
  textToParse = textToParse.replace(/<think>[\s\S]*?<\/think>/gs, '');
  // 移除开头可能的引用块
  textToParse = textToParse.replace(/^>\s*思考中\s*\.*([\r\n]+|$)/m, "");
  textToParse = textToParse.trim();

  // 提取 markdown json 块
// 增强版正则：不管AI前后说了什么废话，只要里面有 ```json 块，就能精准扣出来
const fencedJsonMatch = textToParse.match(/```(?:json)?\s*
  if (fencedJsonMatch && fencedJsonMatch[1]) {
    textToParse = fencedJsonMatch[1].trim();
  }

  // 尝试解析JSON
  try {
    const parsedJson = JSON.parse(textToParse);
    if (parsedJson && typeof parsedJson.summary === 'string' && typeof parsedJson.note === 'string') {
      parsedDataForNextNode = parsedJson;
      item.json.parsing_error_details = null;
      // 解析成功，重置重试计数（或者保持0）
      item.json.ai_retry_count = 0;
      item.json.trigger_ai_retry = false;
    } else {
      throw new Error("解析的JSON缺少必要的summary和note字段");
    }
  } catch (e) {
    if (item.json.ai_retry_count < MAX_AI_RETRIES) {
      item.json.ai_retry_count = item.json.ai_retry_count + 1;
      item.json.trigger_ai_retry = true;
      item.json.parsing_error_details = `JSON解析失败，第${item.json.ai_retry_count}次重试: ${e.message}`;
    } else {
      item.json.trigger_ai_retry = false;
      item.json.parsing_error_details = `JSON解析失败，已达最大重试次数: ${e.message}`;
    }
  }

  item.json.output = parsedDataForNextNode;

  // 如果触发重试，必须把原始文稿带上，因为AI Agent把之前的文稿也“吞”了
  if (item.json.trigger_ai_retry) {
    item.json.video_transcript = original_video_transcript;
  }
}

return items;

const items = $input.all();
for (const item of items) {
  // yt-dlp --print 会按行输出信息
  // 我们按顺序请求了: title, uploader, duration
  const outputLines = (item.json.stdout || "").trim().split('\n');

  item.json.video_title = outputLines[0] || "未知标题";
  item.json.video_author = outputLines[1] || "未知作者";
  item.json.video_duration = outputLines[2] || "未知时长";

  // 整理成最终输出格式，只保留这三个字段
  item.json = {
    video_title: item.json.video_title,
    video_author: item.json.video_author,
    video_duration: item.json.video_duration,
    link: $('Webhook').item.json.body.metadata.link
  };
}
return items;

const items = $input.all();
const newItems = [];

for (const item of items) {
  const rawLocalFile = item.json.body.metadata.local_file;
  if (rawLocalFile) {
    const files = rawLocalFile.split(',').map(f => f.trim()).filter(f => f);
    for (const file of files) {
       const newItem = { json: JSON.parse(JSON.stringify(item.json)) };
       newItem.json.audio_file_path_for_subflow = `/home/node/uploads/${file}`;
       newItems.push(newItem);
    }
  }
}
return newItems;

const items = $input.all();
const parts = [
  { "text": "Please transcribe all text from this image/document verbatim. Do not add any commentary." }
];

for (const item of items) {
  if (item.binary && item.binary.data) {
    parts.push({
      "inline_data": {
        "mime_type": item.binary.data.mimeType,
        "data": item.binary.data.data
      }
    });
  }
}

return [{
   json: {
     gemini_parts: parts
   }
}];

